/// <summary>
///
/// </summary>
public void clicked()
{
    Args                            args;
    Object                          formRun;

    ETG_BankCurrencyRevData         eTG_BankCurrencyRevalData;
    ETG_BankCurrencyRevalDataTmp    eTG_BankCurrencyRevalDataTmp;
    ExchangeRateType                exchangeRateType;
    super();

    delete_from eTG_BankCurrencyRevalDataTmp;

    while select eTG_BankCurrencyRevalData
           where eTG_BankCurrencyRevalData.TransDate == FromDate.dateValue() &&
                 eTG_BankCurrencyRevalData.ExchangeRateDate == ExchRateDate.dateValue()
    {
        eTG_BankCurrencyRevalDataTmp.TransDate                          = eTG_BankCurrencyRevalData.TransDate;
        eTG_BankCurrencyRevalDataTmp.ExchangeRateDate                   = eTG_BankCurrencyRevalData.ExchangeRateDate;
        eTG_BankCurrencyRevalDataTmp.LegalEntity                        = eTG_BankCurrencyRevalData.LegalEntity;
        eTG_BankCurrencyRevalDataTmp.BankAccountId                      = eTG_BankCurrencyRevalData.BankAccountId;
        eTG_BankCurrencyRevalDataTmp.MainAccountNum                     = eTG_BankCurrencyRevalData.MainAccountNum;
        eTG_BankCurrencyRevalDataTmp.BankLedgerDimension                = eTG_BankCurrencyRevalData.BankLedgerDimension;
        eTG_BankCurrencyRevalDataTmp.DefaultDimension                   = eTG_BankCurrencyRevalData.DefaultDimension;
        eTG_BankCurrencyRevalDataTmp.ReportingCurrencyAmount            = eTG_BankCurrencyRevalData.ReportingCurrencyAmount;
        eTG_BankCurrencyRevalDataTmp.ExchangeRateType                   = eTG_BankCurrencyRevalData.ExchangeRateType;

        select firstonly exchangeRateType 
                   where exchangeRateType.RecId == eTG_BankCurrencyRevalData.ExchangeRateType;
        eTG_BankCurrencyRevalDataTmp.Name                               = exchangeRateType.Name;
        eTG_BankCurrencyRevalDataTmp.ETGReportExchangeType              = exchangeRateType.Name;
        eTG_BankCurrencyRevalDataTmp.Companyname                        = eTG_BankCurrencyRevalData.Name;
        eTG_BankCurrencyRevalDataTmp.AccountingCurrencyAmount           = eTG_BankCurrencyRevalData.AccountingCurrencyAmount;
        eTG_BankCurrencyRevalDataTmp.BankCurrencyAmount                 = eTG_BankCurrencyRevalData.AccountingCurrencyAmount;
        eTG_BankCurrencyRevalDataTmp.ReportingCurrencyAmount            = eTG_BankCurrencyRevalData.ReportingCurrencyAmount;
        eTG_BankCurrencyRevalDataTmp.AccountingCurrencyAdjustmentAmount = eTG_BankCurrencyRevalData.AccountingCurrencyAdjustmentAmount;
        eTG_BankCurrencyRevalDataTmp.ReportingCurrencyAdjustmentAmount  = eTG_BankCurrencyRevalData.ReportingCurrencyAdjustmentAmount;
        eTG_BankCurrencyRevalDataTmp.AccountingCurrencyCrossRate        = eTG_BankCurrencyRevalData.AccountingCurrencyCrossRate;
        eTG_BankCurrencyRevalDataTmp.ReportingCurrencyCrossRate         = eTG_BankCurrencyRevalData.ReportingCurrencyCrossRate;
        eTG_BankCurrencyRevalDataTmp.ReportingCurrencyExchangeRateType  = eTG_BankCurrencyRevalData.ReportingCurrencyExchangeRateType;
        eTG_BankCurrencyRevalDataTmp.BankCurrencyCode                   = eTG_BankCurrencyRevalData.BankCurrencyCode;
        eTG_BankCurrencyRevalDataTmp.ReportingCurrencyAdjustmentAmount  = round((eTG_BankCurrencyRevalData.BankCurrencyAmount * eTG_BankCurrencyRevalData.ReportingCurrencyCrossRate)/100- eTG_BankCurrencyRevalData.ReportingCurrencyAmount,0.00001);
        eTG_BankCurrencyRevalDataTmp.ETGNewReportingCurrency            = eTG_BankCurrencyRevalDataTmp.ReportingCurrencyAdjustmentAmount + eTG_BankCurrencyRevalData.ReportingCurrencyAmount;
        eTG_BankCurrencyRevalDataTmp.AccountingCurrencyAdjustmentAmount = round((eTG_BankCurrencyRevalData.BankCurrencyAmount * eTG_BankCurrencyRevalData.AccountingCurrencyCrossRate)/100- eTG_BankCurrencyRevalData.AccountingCurrencyAmount,0.00001);
        eTG_BankCurrencyRevalDataTmp.ETGNewAccountngCurrency            = eTG_BankCurrencyRevalDataTmp.AccountingCurrencyAdjustmentAmount + eTG_BankCurrencyRevalData.AccountingCurrencyCrossRate;
        eTG_BankCurrencyRevalDataTmp.insert();
    }

    args = new Args();
    args.name(formstr(ETG_BankCurrencyRevaluation));
    formRun = classfactory.formRunClass(args);
    formRun.init();
    formRun.run();
    formRun.wait();

}
